#!/usr/bin/env python3
"""Fix: Login now returns properties immediately (no refresh needed)"""
import base64, os, sys

if not os.path.exists("backend/main.py"):
    print("Error: Run this from ~/seller-portal"); sys.exit(1)

data = ""
content = base64.b64decode(data)
with open("backend/main.py", "wb") as f:
    f.write(content)
print(f"  Updated: backend/main.py ({len(content):,} bytes)")
print()
print("Now run:")
print('  git add -A && git commit -m "Fix: login returns properties immediately" && git push')
